#include <gtest/gtest.h>

#include <filesystem>

#include "storage/redis_metadata.h"
#include "storage/storage.h"
#include "types/redis_hash.h"
#include "types/redis_zset.h"

TEST(Compact, Filter) {
  Config config;
  config.db_dir = "compactdb";
  config.slot_id_encoded = false;

  auto storage = std::make_unique<engine::Storage>(&config);
  Status s = storage->Open();
  assert(s.IsOK());

  uint64_t ret = 0;
  std::string ns = "test_compact";
  auto hash = std::make_unique<redis::Hash>(storage.get(), ns);
  std::string expired_hash_key = "expire_hash_key";
  std::string live_hash_key = "live_hash_key";

  engine::Context ctx(storage.get());

  hash->Set(ctx, expired_hash_key, "f1", "v1", &ret);
  hash->Set(ctx, expired_hash_key, "f2", "v2", &ret);
  auto st = hash->Expire(ctx, expired_hash_key, 1);  // expired
  usleep(10000);
  hash->Set(ctx, live_hash_key, "f1", "v1", &ret);
  hash->Set(ctx, live_hash_key, "f2", "v2", &ret);

  auto status = storage->Compact(nullptr, nullptr, nullptr);
  assert(status.ok());
  // Compact twice to workaround issue fixed by: https://github.com/facebook/rocksdb/pull/11468
  status = storage->Compact(nullptr, nullptr, nullptr);
  assert(status.ok());

  rocksdb::DB* db = storage->GetDB();
  rocksdb::ReadOptions read_options;
  read_options.snapshot = db->GetSnapshot();
  read_options.fill_cache = false;

  auto new_iterator = [db, read_options, &storage](ColumnFamilyID column_family_id) {
    return std::unique_ptr<rocksdb::Iterator>(db->NewIterator(read_options, storage->GetCFHandle(column_family_id)));
  };

  auto iter = new_iterator(ColumnFamilyID::Metadata);
  for (iter->SeekToFirst(); iter->Valid(); iter->Next()) {
    auto [user_ns, user_key] = ExtractNamespaceKey(iter->key(), storage->IsSlotIdEncoded());
    EXPECT_EQ(user_key.ToString(), live_hash_key);
  }

  iter = new_iterator(ColumnFamilyID::PrimarySubkey);
  for (iter->SeekToFirst(); iter->Valid(); iter->Next()) {
    InternalKey ikey(iter->key(), storage->IsSlotIdEncoded());
    EXPECT_EQ(ikey.GetKey().ToString(), live_hash_key);
  }

  auto zset = std::make_unique<redis::ZSet>(storage.get(), ns);
  std::string expired_zset_key = "expire_zset_key";
  std::vector<MemberScore> member_scores = {MemberScore{"z1", 1.1}, MemberScore{"z2", 0.4}};
  zset->Add(ctx, expired_zset_key, ZAddFlags::Default(), &member_scores, &ret);
  st = zset->Expire(ctx, expired_zset_key, 1);  // expired
  usleep(10000);

  // Same as the above compact, need to compact twice here
  status = storage->Compact(nullptr, nullptr, nullptr);
  EXPECT_TRUE(status.ok());
  status = storage->Compact(nullptr, nullptr, nullptr);
  EXPECT_TRUE(status.ok());

  iter = new_iterator(ColumnFamilyID::PrimarySubkey);
  for (iter->SeekToFirst(); iter->Valid(); iter->Next()) {
    InternalKey ikey(iter->key(), storage->IsSlotIdEncoded());
    EXPECT_EQ(ikey.GetKey().ToString(), live_hash_key);
  }

  iter = new_iterator(ColumnFamilyID::SecondarySubkey);
  for (iter->SeekToFirst(); iter->Valid(); iter->Next()) {
    EXPECT_TRUE(false);  // never reach here
  }

  // Verify search column family compaction filter can recycle orphaned index entries
  // (e.g. index was dropped but some entries still exist).
  {
    auto search_cf = storage->GetCFHandle(ColumnFamilyID::Search);
    // Create metadata for an indexed JSON key
    redis::IndexMetadata idx_meta;
    idx_meta.on_data_type = redis::IndexOnDataType::JSON;
    std::string encoded_meta;
    idx_meta.Encode(&encoded_meta);

    // Build a fake index meta key in search CF: <ns_len><ns><type=INDEX_META><idx_name>
    std::string idx_name = "orphidx";
    std::string search_index_meta_key;
    PutFixed8(&search_index_meta_key, static_cast<uint8_t>(ns.size()));
    search_index_meta_key.append(ns);
    PutFixed8(&search_index_meta_key, static_cast<uint8_t>(redis::SearchSubkeyType::INDEX_META));
    PutFixed32(&search_index_meta_key, static_cast<uint32_t>(idx_name.size()));
    search_index_meta_key.append(idx_name);

    ASSERT_TRUE(storage->GetDB()->Put(rocksdb::WriteOptions(), search_cf, search_index_meta_key, encoded_meta).ok());

    // Build a fake tag field index entry: <ns_len><ns><type=FIELD><idx_name><field><tag><user_key>
    std::string field = "a";
    std::string tag = "x";
    std::string user_key = "idxtestjson:k_orphan";
    std::string search_entry_key;
    PutFixed8(&search_entry_key, static_cast<uint8_t>(ns.size()));
    search_entry_key.append(ns);
    PutFixed8(&search_entry_key, static_cast<uint8_t>(redis::SearchSubkeyType::FIELD));
    PutFixed32(&search_entry_key, static_cast<uint32_t>(idx_name.size()));
    search_entry_key.append(idx_name);
    PutFixed32(&search_entry_key, static_cast<uint32_t>(field.size()));
    search_entry_key.append(field);
    PutFixed32(&search_entry_key, static_cast<uint32_t>(tag.size()));
    search_entry_key.append(tag);
    PutFixed32(&search_entry_key, static_cast<uint32_t>(user_key.size()));
    search_entry_key.append(user_key);

    ASSERT_TRUE(storage->GetDB()->Put(rocksdb::WriteOptions(), search_cf, search_entry_key, Slice()).ok());

    // Ensure the entry exists before compaction
    std::string tmp;
    ASSERT_TRUE(storage->GetDB()->Get(rocksdb::ReadOptions(), search_cf, search_entry_key, &tmp).ok());

    // Remove index meta to simulate dropped index
    ASSERT_TRUE(storage->GetDB()->Delete(rocksdb::WriteOptions(), search_cf, search_index_meta_key).ok());

    // Compact twice to ensure bottommost level is compacted
    auto s1 = storage->Compact(search_cf, nullptr, nullptr);
    ASSERT_TRUE(s1.ok());
    auto s2 = storage->Compact(search_cf, nullptr, nullptr);
    ASSERT_TRUE(s2.ok());

    // After compaction, orphaned entry should be removed
    auto s3 = storage->GetDB()->Get(rocksdb::ReadOptions(), search_cf, search_entry_key, &tmp);
    ASSERT_TRUE(s3.IsNotFound());
  }

  Slice mk_with_ttl = "mk_with_ttl";
  hash->Set(ctx, mk_with_ttl, "f1", "v1", &ret);
  hash->Set(ctx, mk_with_ttl, "f2", "v2", &ret);

  int retry = 2;
  while (retry-- > 0) {
    status = storage->Compact(nullptr, nullptr, nullptr);
    ASSERT_TRUE(status.ok());
    std::vector<FieldValue> fieldvalues;
    auto get_res = hash->GetAll(ctx, mk_with_ttl, &fieldvalues);
    auto s_expire = hash->Expire(ctx, mk_with_ttl, 1);  // expired immediately..

    if (retry == 1) {
      ASSERT_TRUE(get_res.ok());  // not expired first time
      ASSERT_TRUE(s_expire.ok());
    } else {
      ASSERT_TRUE(get_res.ok());  // expired but still return ok....
      ASSERT_EQ(0, fieldvalues.size());
      ASSERT_TRUE(s_expire.IsNotFound());
    }
    usleep(10000);
  }

  db->ReleaseSnapshot(read_options.snapshot);
  std::error_code ec;
  std::filesystem::remove_all(config.db_dir, ec);
  if (ec) {
    std::cout << "Encounter filesystem error: " << ec << std::endl;
  }
}

