bool SearchFilter::Filter([[maybe_unused]] int level, const Slice &key, [[maybe_unused]] const Slice &value,
                          [[maybe_unused]] std::string *new_value, [[maybe_unused]] bool *modified) const {
  // Search CF keys are encoded as:
  // <ns_len><ns><subkey_type><...>
  // For FIELD entries, we keep them only when their index metadata still exists.

  if (key.empty()) return false;

  Slice input(key);
  uint8_t ns_len = 0;
  if (!GetFixed8(&input, &ns_len)) return false;
  if (input.size() < ns_len + 1) return false;

  std::string ns(input.data(), ns_len);
  input.remove_prefix(ns_len);

  uint8_t type_u8 = 0;
  if (!GetFixed8(&input, &type_u8)) return false;
  auto type = static_cast<redis::SearchSubkeyType>(type_u8);

  if (type != redis::SearchSubkeyType::FIELD) {
    // For now, keep other types.
    return false;
  }

  // FIELD: <index><field><...>
  std::string_view index;
  if (!GetSizedString(&input, &index)) return false;

  // Check whether index metadata exists.
  auto db = stor_->GetDB();
  if (!db) return false;
  auto *search_cf = stor_->GetCFHandle(ColumnFamilyID::Search);

  std::string index_meta_key;
  PutFixed8(&index_meta_key, static_cast<uint8_t>(ns.size()));
  index_meta_key.append(ns);
  PutFixed8(&index_meta_key, static_cast<uint8_t>(redis::SearchSubkeyType::INDEX_META));
  PutSizedString(&index_meta_key, index);

  std::string tmp;
  auto s = db->Get(rocksdb::ReadOptions(), search_cf, index_meta_key, &tmp);
  return s.IsNotFound();
}

}  // namespace engine

